import React from 'react'
import { Layout } from 'antd';
const { Content, Sider } = Layout;
export default function Chat() {
  return (
    <Content
      style={{
        padding: '0 50px',
        marginTop: "30px"
      }}
    >
      <Layout
        style={{
          height: "100%",
          padding: '24px 0',
          backgroundColor: "rgb(255,255,255,0.5)",
          backdropFilter:"blur(10px)",
          WebkitBackdropFilter:"blur(10px)"
        }}
      >
        <Sider
          width={300}
          style={{
            backgroundColor: "transparent",
            fontSize: '20px'
          }}
        >
          <div
            id="scrollableDiv"
            style={{
              height: "100%",
              overflow: 'auto',
              padding: '0 16px',
              marginLeft: '20px',
              border: '1px solid rgba(140, 140, 140, 0.35)',
            }}
          >
            <Button size='large' ghost style={{width:'100%', borderColor:'rgba(140, 140, 140, 0.35)',marginTop:'10px'}}>ADD</Button>
            <InfiniteScroll
              dataLength={firendList.length}
              next={LoadContactList}
              hasMore={firendList.length < 50}
              loader={
                <Skeleton
                  avatar
                  paragraph={{
                    rows: 1,
                  }}
                  active
                />
              }
              endMessage={<Divider plain>It is all, nothing more 🤐</Divider>}
              scrollableTarget="scrollableDiv"
            >
              <List
                dataSource={firendList}
                renderItem={(item) => (
                  <List.Item>
                    <List.Item.Meta
                      title={item.username}
                    />
                    <div onClick={() => setSelectedUser(item)}>Content</div>
                  </List.Item>
                )}
              />
            </InfiniteScroll>
          </div>
        </Sider>
        <Content
        >
        </Content>
      </Layout>
    </Content>
  )
}
